    /**
     * @brief 检查连接是否活跃
     * @return 如果连接正常返回true
     */
    virtual bool IsAlive() const = 0;

    /**
     * @brief 关闭连接
     */
    virtual void Close() = 0;

    /**
     * @brief 获取往返延迟（毫秒）
     * @return 延迟值
     */
    virtual float GetLatency() const = 0;
};

