 * @file physics_server.h
 * @brief 物理服务器核心 - 服务器权威物理模拟
 * 
 * 本文件定义了物理服务器的核心类，负责：
 * 1. 运行确定性物理模拟（使用Jolt Physics）
 * 2. 接收客户端输入并处理
 * 3. 广播物理状态给所有客户端
 * 4. 管理玩家连接
 * 
 * 架构：服务器权威模式
 * - 服务器是物理世界的唯一权威
 * - 客户端发送输入，服务器计算结果
 * - 服务器定期广播世界快照
 */

#pragma once

#include "../common/physics_state.h"
#include "../common/timestep_manager.h"
#include "../common/deterministic_random.h"
#include <memory>
#include <vector>
#include <unordered_map>
#include <functional>
#include <mutex>
#include <atomic>

namespace PhysicsSync {

// ================================================================
// 前向声明
// ================================================================

class ServerConnection;
class PhysicsWorld;

/**
 * @brief 物理服务器核心类
 * 
 * 这是服务器的主控制类，管理整个物理世界的模拟和网络通信。
 * 它运行在一个独立的线程中，以固定频率更新物理世界。
 * 
 * 线程模型：
 * - 主线程：网络I/O（接收输入，发送快照）
 * - 模拟线程：物理更新（以固定频率运行）
 */
class PhysicsServer {
public:
    /**
     * @brief 构造函数
     * @param physicsHz 物理更新频率（默认60Hz）
     * @param snapshotHz 快照广播频率（默认30Hz，即每2个物理tick广播一次）
     */
    PhysicsServer(uint32_t physicsHz = 60, uint32_t snapshotHz = 30);

    /**
     * @brief 析构函数
     */
    ~PhysicsServer();

    // 禁止拷贝
    PhysicsServer(const PhysicsServer&) = delete;
    PhysicsServer& operator=(const PhysicsServer&) = delete;

    /**
     * @brief 初始化服务器
     * @return 是否成功初始化
     */
    bool Initialize();

    /**
     * @brief 启动服务器（开始模拟）
     */
    void Start();

    /**
     * @brief 停止服务器
     */
    void Stop();

    /**
     * @brief 检查服务器是否运行中
     * @return 如果运行中返回true
     */
    bool IsRunning() const { return running_.load(); }

    /**
     * @brief 添加一个玩家连接
     * @param connection 连接对象
     * @return 玩家ID，如果失败返回0
     */
    uint32_t AddPlayer(std::shared_ptr<ServerConnection> connection);

    /**
     * @brief 移除一个玩家连接
     * @param playerId 玩家ID
     */
    void RemovePlayer(uint32_t playerId);

    /**
     * @brief 接收玩家输入
     * @param input 输入数据
     * @return 是否成功接收
     */
    bool ReceiveInput(const PlayerInput& input);

    /**
     * @brief 获取当前物理tick
     * @return 当前tick序号
     */
    uint32_t GetCurrentTick() const { return timeManager_.GetCurrentTick(); }

    /**
     * @brief 获取物理世界快照
     * @param snapshot 输出参数
     * @return 是否有新快照
     */
    bool GetSnapshot(PhysicsWorldSnapshot& snapshot);

    /**
     * @brief 获取当前连接的玩家数量
     * @return 玩家数量
     */
    uint32_t GetPlayerCount() const;

    /**
     * @brief 设置物理世界配置
     * @param gravity 重力向量
     * @param iterationCount 求解器迭代次数
     */
    void SetPhysicsConfig(Vec3 gravity, uint32_t iterationCount);

    /**
     * @brief 获取服务器统计信息
     * @return 统计信息字符串
     */
    std::string GetStatistics() const;

    /**
     * @brief 创建初始物理世界
     * 
     * 用于测试，创建一个简单的场景。
     */
    void CreateDefaultWorld();

private:
    /**
     * @brief 模拟线程函数
     * 
     * 在独立线程中运行，以固定频率更新物理世界。
     */
    void SimulationThread();

    /**
     * @brief 处理所有待处理的输入
     */
    void ProcessPendingInputs();

    /**
     * @brief 构建世界快照
     * @param snapshot 输出参数
     */
    void BuildSnapshot(PhysicsWorldSnapshot& snapshot);

    /**
     * @brief 广播快照给所有玩家
     * @param snapshot 快照数据
     */
    void BroadcastSnapshot(const PhysicsWorldSnapshot& snapshot);

    // 配置参数
    uint32_t physicsHz_;                ///< 物理更新频率
    uint32_t snapshotHz_;               ///< 快照广播频率
    uint32_t snapshotInterval_;         ///< 快照间隔（tick数）

    // 时间管理
    TimeStepManager timeManager_;       ///< 时间步长管理器

    // 物理世界（使用Jolt Physics）
    std::unique_ptr<PhysicsWorld> physicsWorld_;

    // 玩家管理
    std::unordered_map<uint32_t, std::shared_ptr<ServerConnection>> players_;
    uint32_t nextPlayerId_;
    std::mutex playersMutex_;

    // 输入处理
    std::vector<PlayerInput> pendingInputs_;
    std::mutex inputMutex_;

    // 快照
    PhysicsWorldSnapshot currentSnapshot_;
    uint32_t lastSnapshotTick_;
    std::mutex snapshotMutex_;

    // 确定性随机数
    DeterministicRandom deterministicRng_;

    // 控制标志
    std::atomic<bool> running_;
    std::unique_ptr<std::thread> simulationThread_;
};

/**
 * @brief 服务器连接接口
 * 
 * 每个玩家连接一个此对象。
 * 负责与该客户端的网络通信。
 */
class ServerConnection {
public:
    virtual ~ServerConnection() = default;

    /**
     * @brief 发送数据给客户端
     * @param data 数据指针
     * @param size 数据大小
     * @return 是否成功
     */
    virtual bool Send(const uint8_t* data, size_t size) = 0;

    /**
     * @brief 接收数据从客户端
     * @param buffer 输出缓冲区
     * @param maxSize 最大接收大小
     * @return 实际接收的字节数，-1表示错误
     */
    virtual int32_t Receive(uint8_t* buffer, size_t maxSize) = 0;

    /**
     * @brief 检查连接是否活跃
     * @return 如果连接正常返回true
     */
    virtual bool IsAlive() const = 0;

    /**
     * @brief 关闭连接
     */
    virtual void Close() = 0;

    /**
     * @brief 获取往返延迟（毫秒）
     * @return 延迟值
     */
    virtual float GetLatency() const = 0;
};

} // namespace PhysicsSync",
