        simulationThread_->join();
    }
    if (networkThread_ && networkThread_->joinable()) {
        networkThread_->join();
    }

    // 关闭所有玩家连接
    {
        std::lock_guard<std::mutex> lock(playersMutex_);
        for (auto& [id, player] : players_) {
