// ================================================================
// 私有线程实现
// ================================================================

void PhysicsServer::NetworkThread() {
    std::cout << "[PhysicsServer] Network thread started." << std::endl;

    uint32_t playerIdCounter = 1;

    while (running_.load() && networkRunning_.load()) {
