#include "physics_server.h"
#include <thread>
#include <iostream>
#include <sstream>
#include <algorithm>

namespace PhysicsSync {

// =====================================================================
// PhysicsServer 实现
// =====================================================================

PhysicsServer::PhysicsServer(uint32_t physicsHz, uint32_t snapshotHz)
    : physicsHz_(physicsHz)
    , snapshotHz_(snapshotHz)
    , snapshotInterval_(physicsHz / snapshotHz)  // 每N个tick广播一次
    , nextPlayerId_(1)
    , lastSnapshotTick_(0)
    , running_(false)
    , deterministicRng_(42)  // 固定种子确保确定性
{
    timeManager_.SetFixedTimeStep(static_cast<float>(physicsHz));
}

PhysicsServer::~PhysicsServer() {
    Stop();
}

bool PhysicsServer::Initialize() {
    std::cout << "[PhysicsServer] Initializing..." << std::endl;

    // 创建默认物理世界
    CreateDefaultWorld();

    std::cout << "[PhysicsServer] Initialization complete." << std::endl;
    return true;
}

void PhysicsServer::Start() {
    if (running_.load()) {
        std::cout << "[PhysicsServer] Already running." << std::endl;
        return;
    }

    std::cout << "[PhysicsServer] Starting simulation thread..." << std::endl;
    running_.store(true);
    simulationThread_ = std::make_unique<std::thread>(
        &PhysicsServer::SimulationThread, this);
}

void PhysicsServer::Stop() {
    if (!running_.load()) {
        return;
    }

    std::cout << "[PhysicsServer] Stopping..." << std::endl;
    running_.store(false);

    if (simulationThread_ && simulationThread_->joinable()) {
        simulationThread_->join();
    }

    std::cout << "[PhysicsServer] Stopped." << std::endl;
}

uint32_t PhysicsServer::AddPlayer(std::shared_ptr<ServerConnection> connection) {
    std::lock_guard<std::mutex> lock(playersMutex_);

    uint32_t playerId = nextPlayerId_++;
    players_[playerId] = connection;

    std::cout << "[PhysicsServer] Player " << playerId 
              << " connected. Total players: " << players_.size() << std::endl;

    return playerId;
}

void PhysicsServer::RemovePlayer(uint32_t playerId) {
    std::lock_guard<std::mutex> lock(playersMutex_);
    players_.erase(playerId);

    std::cout << "[PhysicsServer] Player " << playerId 
              << " disconnected. Total players: " << players_.size() << std::endl;
}

bool PhysicsServer::ReceiveInput(const PlayerInput& input) {
    std::lock_guard<std::mutex> lock(inputMutex_);
    pendingInputs_.push_back(input);
    return true;
}

bool PhysicsServer::GetSnapshot(PhysicsWorldSnapshot& snapshot) {
    std::lock_guard<std::mutex> lock(snapshotMutex_);

    // 检查是否有新的快照
    if (currentSnapshot_.snapshotId == lastSnapshotTick_) {
        return false;
    }

    snapshot = currentSnapshot_;
    return true;
}

uint32_t PhysicsServer::GetPlayerCount() const {
    std::lock_guard<std::mutex> lock(playersMutex_);
    return static_cast<uint32_t>(players_.size());
}

void PhysicsServer::SetPhysicsConfig(Vec3 gravity, uint32_t iterationCount) {
    // 注意：实际项目中这里会配置Jolt Physics的物理参数
    // 当前为简化实现，暂不实现具体逻辑
    (void)gravity;
    (void)iterationCount;
}

std::string PhysicsServer::GetStatistics() const {
    std::ostringstream oss;
    oss << "=== PhysicsServer Statistics ===" << std::endl;
    oss << timeManager_.GetStatistics();

    std::lock_guard<std::mutex> lock(playersMutex_);
    oss << "Players: " << players_.size() << std::endl;
    oss << "Pending Inputs: " << pendingInputs_.size() << std::endl;
    oss << "Snapshot ID: " << currentSnapshot_.snapshotId << std::endl;
    oss << "Objects in Snapshot: " << currentSnapshot_.objects.size() << std::endl;

    return oss.str();
}

void PhysicsServer::CreateDefaultWorld() {
    // 创建初始物理对象（测试用）
    currentSnapshot_.Clear();

    // 添加一个玩家角色
    PhysicsObjectState playerState(
        1,                              // objectId
        Vec3{0.0f, 2.0f, 0.0f},         // 初始位置
        Quat::Identity(),               // 初始旋转
        PhysicsObjectType::PLAYER       // 类型
    );
    currentSnapshot_.AddObject(playerState);

    // 添加一个动态物体（球）
    PhysicsObjectState ballState(
        2,                              // objectId
        Vec3{5.0f, 5.0f, 0.0f},         // 初始位置
        Quat::Identity(),               // 初始旋转
        PhysicsObjectType::DYNAMIC      // 类型
    );
    ballState.linearVelocity = Vec3{1.0f, 0.0f, 0.0f};  // 初始速度
    currentSnapshot_.AddObject(ballState);

    // 添加静态地面
    PhysicsObjectState groundState(
        3,                              // objectId
        Vec3{0.0f, -1.0f, 0.0f},        // 位置
        Quat::Identity(),               // 旋转
        PhysicsObjectType::STATIC       // 类型
    );
    currentSnapshot_.AddObject(groundState);

    lastSnapshotTick_ = currentSnapshot_.snapshotId;
    std::cout << "[PhysicsServer] Created default world with " 
              << currentSnapshot_.objects.size() << " objects." << std::endl;
}

void PhysicsServer::SimulationThread() {
    std::cout << "[PhysicsServer] Simulation thread started." << std::endl;

    auto lastFrameTime = std::chrono::high_resolution_clock::now();

    while (running_.load()) {
        auto now = std::chrono::high_resolution_clock::now();
        std::chrono::duration<float> deltaTime = now - lastFrameTime;
        lastFrameTime = now;

        // 防止deltaTime过大（例如调试时暂停）
        float dt = std::min(deltaTime.count(), 0.1f);

        // 开始新帧
        timeManager_.StartNewFrame(dt);

        // 处理所有物理tick
        while (timeManager_.ShouldTick()) {
            // 处理待处理的输入
            ProcessPendingInputs();

            // 更新物理世界
            // 注意：这里应该是Jolt Physics的更新调用
            // 简化实现：仅更新快照时间戳
            currentSnapshot_.timestamp = 
                static_cast<uint32_t>(timeManager_.GetCurrentTick());

            // 执行tick
            timeManager_.Tick();
        }

        // 每隔snapshotInterval_个tick构建快照
        if (timeManager_.GetCurrentTick() % snapshotInterval_ == 0) {
            BuildSnapshot(currentSnapshot_);
        }

        // 结束帧
        timeManager_.FinishFrame();

        // 小休眠，防止CPU占用过高
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
    }

    std::cout << "[PhysicsServer] Simulation thread stopped." << std::endl;
}

void PhysicsServer::ProcessPendingInputs() {
    std::lock_guard<std::mutex> lock(inputMutex_);

    for (const auto& input : pendingInputs_) {
        // 处理玩家输入
        // 实际项目中这里会根据输入更新刚体速度/力
        // 简化实现：仅打印
        if (input.playerId == 1 && (input.moveX != 0.0f || input.moveY != 0.0f)) {
            // 找到玩家对象并更新速度
            auto* playerObj = currentSnapshot_.FindObject(input.playerId);
            if (playerObj) {
                playerObj->linearVelocity.x = input.moveX * 5.0f;
                playerObj->linearVelocity.y = input.moveY * 5.0f;
            }
        }
    }

    pendingInputs_.clear();
}

void PhysicsServer::BuildSnapshot(PhysicsWorldSnapshot& snapshot) {
    // 在实际项目中，这里会从Jolt Physics获取最新状态
    // 简化实现：快照已经是最新的

    snapshot.snapshotId = timeManager_.GetCurrentTick();
    snapshot.objectCount = static_cast<uint32_t>(snapshot.objects.size());

    std::cout << "[PhysicsServer] Built snapshot " << snapshot.snapshotId 
              << " with " << snapshot.objectCount << " objects." << std::endl;
}

void PhysicsServer::BroadcastSnapshot(const PhysicsWorldSnapshot& snapshot) {
    std::lock_guard<std::mutex> lock(playersMutex_);

    // 序列化快照
    std::vector<uint8_t> buffer;
    snapshot.Serialize(buffer);

    // 发送给所有玩家
    for (auto& [playerId, connection] : players_) {
        if (connection && connection->IsAlive()) {
            connection->Send(buffer.data(), buffer.size());
        }
    }
}

} // namespace PhysicsSync
