        "+                    }",
        "+                    break;",
        "+                }",
        "+",
        "+                case ServerMessageType::WORLD_SNAPSHOT: {",
        "+                    auto* snapMsg = dynamic_cast<WorldSnapshotMessage*>(msg.get());",
        "+                    if (snapMsg && !snapMsg->stateData.empty()) {",
