TEST(ClientIntegrationTest, ClientConfig) {
    ClientConfig config("127.0.0.1", 9300);
    EXPECT_EQ(config.serverHost, "127.0.0.1");
    EXPECT_EQ(config.serverPort, 9300);
    EXPECT_EQ(config.physicsHz, 60);

    ClientConfig defaultConfig;
