        "+TEST(ServerIntegrationTest, PhysicsUpdate) {",
        "+    ServerConfig config(9300);",
        "+    config.physicsHz = 60;",
        "+    config.snapshotHz = 30;",
        "+",
        "+    PhysicsServer server(config);",
        "+    server.CreateDefaultWorld();",
