TEST(PhysicsObjectStateTest, PredictPosition) {
    PhysicsObjectState state(1, Vec3{0.0f, 0.0f, 0.0f},
                              Quat::Identity(),
                              PhysicsObjectType::DYNAMIC);
    state.linearVelocity = Vec3{2.0f, 0.0f, 0.0f};  // 2 m/s to the right

