    EXPECT_FLOAT_EQ(predicted.x, 1.0f);  // 2 * 0.5 = 1
    EXPECT_FLOAT_EQ(predicted.y, 0.0f);
    EXPECT_FLOAT_EQ(predicted.z, 0.0f);
}

