        "+",
        "+    // 模拟两帧",
        "+    for (int frame = 0; frame < 2; frame++) {",
        "+        manager.StartNewFrame(fixedStep);  // 每帧正好一个step的时间",
        "+",
        "+        int ticksThisFrame = 0;",
        "+        while (manager.ShouldTick()) {",
        "+            manager.Tick();",
        "+            ticksThisFrame++;",
        "+        }",
        "+",
        "+        // 每帧应该恰好处理一个tick",
        "+        EXPECT_EQ(ticksThisFrame, 1);",
