        "+    float fixedStep = 1.0f / 60.0f;",
        "+",
        "+    // 传入两倍于step的时间，应该累积",
        "+    manager.StartNewFrame(fixedStep * 2.0f);",
        "+",
        "+    // 应该可以处理两个tick",
        "+    int ticksThisFrame = 0;",
        "+    while (manager.ShouldTick()) {",
        "+        manager.Tick();",
